class SAMLResponseParser:
    def __init__(self, saml_response_xml):
        self.root = ET.fromstring(saml_response_xml)
    
    def get_name_id(self):
        name_id = self.root.find('.//saml:Subject/saml:NameID', SAML_NAMESPACES)
        if name_id is not None:
            return name_id.text
        return None
    
    def get_attributes(self):
        attributes = {}
        attribute_statements = self.root.findall('.//saml:AttributeStatement/saml:Attribute', SAML_NAMESPACES)
        
        for attr in attribute_statements:
            attr_name = attr.get('Name')
            attr_values = []
            
            for value in attr.findall('saml:AttributeValue', SAML_NAMESPACES):
                if value.text:
                    attr_values.append(value.text)
            
            if attr_values:
                attributes[attr_name] = attr_values[0] if len(attr_values) == 1 else attr_values
        
        return attributes
    
    def get_session_index(self):
        authn_statement = self.root.find('.//saml:AuthnStatement', SAML_NAMESPACES)
        if authn_statement is not None:
            return authn_statement.get('SessionIndex')
        return None


